import argparse
import os
import time
from pathlib import Path

RETENTION_DAYS = 60


def _is_within(child: Path, parent: Path) -> bool:
    child = child.resolve(strict=False)
    parent = parent.resolve(strict=False)
    return parent == child or parent in child.parents


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--dry-run', action='store_true')
    args = ap.parse_args()

    thumbs = (Path.cwd() / 'assets' / 'generated' / 'thumbs').resolve()
    backup = (Path.cwd() / 'assets' / 'generated' / 'thumbs_backup').resolve()
    cutoff = time.time() - RETENTION_DAYS * 24 * 60 * 60

    candidates = []
    for root, dirs, files in os.walk(thumbs, followlinks=False):
        rootp = Path(root)
        # do not traverse symlinked directories
        dirs[:] = [d for d in dirs if not (rootp / d).is_symlink()]
        for name in files:
            if not name.endswith('.jpg'):
                continue
            p = rootp / name
            if p.is_symlink():
                continue
            rp = p.resolve(strict=False)
            if not _is_within(rp, thumbs):
                continue
            if _is_within(rp, backup):
                continue
            try:
                if rp.stat().st_mtime < cutoff:
                    candidates.append(rp)
            except FileNotFoundError:
                continue

    if args.dry_run:
        for p in candidates:
            print(f"DRY_RUN_DELETE: {p}")
        return

    for p in candidates:
        p.unlink(missing_ok=True)
    print(f"Deleted {len(candidates)} files")


if __name__ == '__main__':
    main()
